args.sparql:
SELECT DISTINCT ?coachTeam WHERE {
  ?player wdt:P39 wd:Q168030 ;
          wdt:P1545 wd:Q8027119 ;
          wdt:P580 ?start;
          wdt:P582 ?end.
  FILTER(?start <= '1951-12-31' && ?end >= '1951-01-01')
  ?player wdt:P166 wd:Q19864195.
  ?player wdt:P39 ?coachPosition;
          wdt:P580 ?coachStart;
          wdt:P582 ?coachEnd.
  ?coachPosition wdt:P1545 ?coachTeam.
  FILTER(?coachStart <= '1969-12-31' && ?coachEnd >= '1967-01-01')
}
